using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

namespace ResearchAgent;

public sealed partial class ResearchTools
{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
    };

    [Description("Search the web for information on a query. Returns text extracted from top search results.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query)
    {
        var encoded = WebUtility.UrlEncode(query);
        var searchUrl = $"https://lite.duckduckgo.com/lite/?q={encoded}";

        try
        {
            var html = await _httpClient.GetStringAsync(searchUrl);
            var text = StripHtml(html);

            const int maxLen = 4000;
            if (text.Length > maxLen)
            {
                text = text[..maxLen] + "\n[truncated]";
            }

            return string.IsNullOrWhiteSpace(text)
                ? $"No results found for '{query}'."
                : $"Search results for '{query}':\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    [Description("Save a research note with a title and content summarizing key findings.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: '{title}'";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            var (title, content) = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, " ");
        text = WebUtility.HtmlDecode(text);
        text = ExcessWhitespaceRegex().Replace(text, " ").Trim();
        return text;
    }

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex ExcessWhitespaceRegex();
}

