using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

var tools = new ResearchTools();
var aiTools = new AIFunction[]
{
    AIFunctionFactory.Create(tools.SearchWebAsync),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Description = "An AI research assistant that searches the web and takes notes.",
    Instructions = """
        You are a research agent. When given a topic, you must:
        1. Search the web for information using multiple targeted queries.
        2. Save important findings as notes using the note-taking tool.
        3. After gathering enough information, retrieve your notes and produce
           a well-structured summary with key points and sources.
        Be thorough — perform at least 2-3 searches from different angles.
        """,
};

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
    Tools = aiTools,
    Temperature = 0f,
};

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

Console.WriteLine();
await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine("Research complete.");

